Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        var client = new HttpClient(_handler) { BaseAddress = new Uri("https://example.com") };
        _sut = new DataFetcher(client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        // Act
        var result = await _sut.FetchAsync("https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.StatusCode = HttpStatusCode.NotFound;

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync("https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_TimeoutViaToken_ThrowsOperationCanceled()
    {
        // Arrange - handler delays longer than the token allows
        _handler.SimulatedDelay = TimeSpan.FromSeconds(10);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com/slow", cts.Token));
    }

    // Minimal test double for HttpMessageHandler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;
        public TimeSpan SimulatedDelay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (SimulatedDelay > TimeSpan.Zero)
            {
                await Task.Delay(SimulatedDelay, cancellationToken);
            }

            return new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| **Async tests** | Return `async Task`, use `await` directly |
| **Timeouts** | `[Timeout(ms)]` + pass `_testContext.CancellationToken` to your code |
| **Cancellation** | Create a pre-cancelled or time-limited `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Constructor injection** | `TestContext` injected via constructor (MSTest 3.6+), enables `readonly` fields |
| **Sealed class** | Performance and design clarity |

The `[Timeout]` attribute automatically cancels `TestContext.CancellationToken` when time expires, so passing it through to your production code ensures hung tests fail cleanly rather than hanging the test run.
